using System;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        var students = new List<string> { "Alice", "Bob", "Charlie", "Diana" };

        students.Add("Eve");
        students.Remove("Bob");
        students.Insert(1, "Frank");

        Console.WriteLine($"Students ({students.Count}):");
        foreach (var s in students)
            Console.WriteLine($"- {s}");

        Console.WriteLine($"Contains Charlie: {students.Contains("Charlie")}");
    }
}
